import React, { useState, useEffect } from 'react';
import AOS from 'aos';
import 'aos/dist/aos.css';
import emailjs from '@emailjs/browser';

const Contact = () => {
    const [formData, setFormData] = useState({ name: '', email: '', subject: '', message: '' });
    const [status, setStatus] = useState({ loading: false, success: null, error: null });

    useEffect(() => {
        AOS.init({ duration: 1000, easing: "ease-in-out", once: true });
    }, []);

    const checkMessageLimit = () => {
        const emailLimitData = JSON.parse(localStorage.getItem("emailLimits")) || {};
        const userEmail = formData.email;
        const today = new Date().toISOString().split('T')[0];

        if (emailLimitData[userEmail] && emailLimitData[userEmail].date === today) {
            return emailLimitData[userEmail].count >= 3;
        }
        return false;
    };

    const updateMessageCount = () => {
        const emailLimitData = JSON.parse(localStorage.getItem("emailLimits")) || {};
        const userEmail = formData.email;
        const today = new Date().toISOString().split('T')[0];

        if (emailLimitData[userEmail] && emailLimitData[userEmail].date === today) {
            emailLimitData[userEmail].count += 1;
        } else {
            emailLimitData[userEmail] = { count: 1, date: today };
        }

        localStorage.setItem("emailLimits", JSON.stringify(emailLimitData));
    };

    const handleChange = (e) => {
        setFormData({ ...formData, [e.target.name]: e.target.value });
    };

    const handleSubmit = (e) => {
        e.preventDefault();

        if (checkMessageLimit()) {
            setStatus({ loading: false, success: null, error: "You can only send 3 messages per day." });
            return;
        }

        setStatus({ loading: true, success: null, error: null });

        emailjs.send(
            'service_iytf57c',
            'template_loii407',
            formData,
            'yXoQAl-S7xEexV7CC'
        )
            .then(() => {
                updateMessageCount();
                setStatus({ loading: false, success: 'Your message has been sent!', error: null });
                setFormData({ name: '', email: '', subject: '', message: '' });
                setTimeout(() => setStatus({ loading: false, success: null, error: null }), 5000);
            })
            .catch((error) => {
                setStatus({ loading: false, success: null, error: 'Failed to send message. Try again later.' });
            });
    };

    return (
        <section id="contact" className="contact section">
            <div className="container section-title" data-aos="fade-up">
                <h2 className="text-gradient">Get In Touch</h2>
                <p>Have a project in mind or just want to say hi? Feel free to reach out!</p>
            </div>

            <div className="container" data-aos="fade-up" data-aos-delay="100">
                <div className="row justify-content-center">
                    <div className="col-lg-8">
                        <div className="contact-card glass-effect p-5" style={{ borderRadius: '24px' }}>
                            <form onSubmit={handleSubmit}>
                                <div className="row gy-4">
                                    <div className="col-md-6">
                                        <div className="form-floating mb-3">
                                            <input 
                                                type="text" 
                                                name="name" 
                                                className="form-control glass-effect text-white border-0" 
                                                id="nameInput"
                                                placeholder="Your Name" 
                                                required 
                                                value={formData.name} 
                                                onChange={handleChange}
                                                style={{ background: 'rgba(255,255,255,0.05)' }}
                                            />
                                            <label htmlFor="nameInput" className="text-muted">Your Name</label>
                                        </div>
                                    </div>
                                    <div className="col-md-6">
                                        <div className="form-floating mb-3">
                                            <input 
                                                type="email" 
                                                className="form-control glass-effect text-white border-0" 
                                                name="email" 
                                                id="emailInput"
                                                placeholder="Your Email" 
                                                required 
                                                value={formData.email} 
                                                onChange={handleChange}
                                                style={{ background: 'rgba(255,255,255,0.05)' }}
                                            />
                                            <label htmlFor="emailInput" className="text-muted">Your Email</label>
                                        </div>
                                    </div>
                                    <div className="col-12">
                                        <div className="form-floating mb-3">
                                            <input 
                                                type="text" 
                                                className="form-control glass-effect text-white border-0" 
                                                name="subject" 
                                                id="subjectInput"
                                                placeholder="Subject" 
                                                required 
                                                value={formData.subject} 
                                                onChange={handleChange}
                                                style={{ background: 'rgba(255,255,255,0.05)' }}
                                            />
                                            <label htmlFor="subjectInput" className="text-muted">Subject</label>
                                        </div>
                                    </div>
                                    <div className="col-12">
                                        <div className="form-floating mb-4">
                                            <textarea 
                                                className="form-control glass-effect text-white border-0" 
                                                name="message" 
                                                id="messageInput"
                                                placeholder="Message" 
                                                style={{ height: '150px', background: 'rgba(255,255,255,0.05)' }} 
                                                required 
                                                value={formData.message} 
                                                onChange={handleChange}
                                            ></textarea>
                                            <label htmlFor="messageInput" className="text-muted">Message</label>
                                        </div>
                                    </div>
                                    <div className="col-12 text-center">
                                        {status.loading && <div className="text-primary mb-3"><i className="bi bi-arrow-repeat spin me-2"></i>Sending...</div>}
                                        {status.error && <div className="alert alert-danger glass-effect border-0 text-danger mb-3">{status.error}</div>}
                                        {status.success && <div className="alert alert-success glass-effect border-0 text-success mb-3">{status.success}</div>}

                                        <button type="submit" disabled={status.loading} className="btn btn-custom px-5 py-3 w-100">
                                            Send Message <i className="bi bi-send ms-2"></i>
                                        </button>
                                    </div>
                                </div>
                            </form>
                        </div>
                    </div>
                </div>
            </div>
        </section>
    );
};

export default Contact;
